.circular-scroll-showcase {
  position: relative;
  width: 100%;
  min-height: 100vh;
  overflow: clip;
  background: #000;
  color: #fff;
}

.circular-scroll-showcase__sticky {
  position: relative;
  height: 100vh;
  width: 100%;
  overflow: hidden;
}

.circular-scroll-showcase__inner {
  position: relative;
  display: flex;
  height: 100%;
  width: 100%;
}

.circular-scroll-showcase__left,
.circular-scroll-showcase__right {
  position: relative;
  height: 100%;
  width: 50vw;
}

.circular-scroll-showcase__left {
  display: flex;
  align-items: center;
  justify-content: center;
  transform: translateX(-60%);
}

.circular-scroll-showcase__right {
  display: flex;
  align-items: center;
  justify-content: center;
  transform: translateX(50%);
}

.circular-scroll-showcase__left-track,
.circular-scroll-showcase__right-track {
  position: relative;
  height: 78vh;
}

.circular-scroll-showcase__left-item,
.circular-scroll-showcase__right-item {
  position: absolute;
  top: 50%;
  left: 50%;
  transform-origin: center center;
  will-change: transform;
}

.circular-scroll-showcase__left-item {
  width: 100%;
  white-space: nowrap;
  text-align: center;
  font-size: var(--css-title-size, clamp(28px, 3vw, 56px));
  font-weight: 500;
  line-height: 1;
  letter-spacing: -0.04em;
  pointer-events: none;
}

.circular-scroll-showcase__right-item {
  width: var(--css-card-width, 210px);
  height: var(--css-card-height, 210px);
  margin-left: calc(var(--css-card-width, 210px) * -0.5);
  margin-top: calc(var(--css-card-height, 210px) * -0.5);
}

.circular-scroll-showcase__card {
  width: 100%;
  height: 100%;
  overflow: hidden;
  border-radius: 18px;
  background: #f5f2eb;
  box-shadow: 0 30px 60px rgba(0, 0, 0, 0.28), 0 8px 20px rgba(0, 0, 0, 0.16);
}

.circular-scroll-showcase__image {
  display: block;
  height: 100%;
  width: 100%;
  object-fit: cover;
  user-select: none;
  pointer-events: none;
}

"use client";

import { useEffect, useMemo, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import "./orbit-slider.css";

gsap.registerPlugin(ScrollTrigger);

function wrapProgress(value) {
  let v = value % 1;
  if (v < 0) v += 1;
  return v;
}

function getCircularPosition(progress, radiusX, radiusY, angleOffset = 0) {
  const angle = progress * Math.PI * 2 + angleOffset;
  return { x: Math.sin(angle) * radiusX, y: Math.cos(angle) * radiusY };
}

export function OrbitSlider({
  items = [],
  className = "",
  sectionHeight = 260,
  leftRadiusX = 95,
  leftRadiusY = 220,
  rightRadiusX = 260,
  rightRadiusY = 260,
  imageCardWidth = 190,
  imageCardHeight = 210,
  titleSize = "clamp(28px, 3vw, 56px)",
  pinSpacing = true,
  scrub = 1.2,
}) {
  const rootRef = useRef(null);
  const stickyRef = useRef(null);

  const safeItems = useMemo(
    () =>
      items.map((item, index) => ({
        id: item.id ?? index,
        title: item.title ?? `Item ${index + 1}`,
        image: item.image ?? "",
        alt: item.alt ?? item.title ?? `Item ${index + 1}`,
      })),
    [items]
  );

  useEffect(() => {
    if (!rootRef.current || !stickyRef.current) return;

    const ctx = gsap.context(() => {
      const leftNodes = gsap.utils.toArray(".circular-scroll-showcase__left-item");
      const rightNodes = gsap.utils.toArray(".circular-scroll-showcase__right-item");
      const total = safeItems.length;
      if (!total) return;

      const render = (scrollP) => {
        leftNodes.forEach((node, index) => {
          const local = wrapProgress(index / total - scrollP);
          const pos = getCircularPosition(local, leftRadiusX, leftRadiusY, Math.PI);
          const depth = Math.cos(local * Math.PI * 2 + Math.PI);

          gsap.set(node, {
            x: pos.x,
            y: pos.y,
            zIndex: Math.round(gsap.utils.mapRange(-1, 1, 1, 30, depth)),
          });
        });

        rightNodes.forEach((node, index) => {
          const local = wrapProgress(index / total - scrollP);
          const pos = getCircularPosition(local, rightRadiusX, rightRadiusY, -Math.PI * 0.08);
          const depth = Math.cos(local * Math.PI * 2 - Math.PI * 0.08);

          gsap.set(node, {
            x: pos.x,
            y: pos.y,
            zIndex: Math.round(gsap.utils.mapRange(-1, 1, 1, 40, depth)),
          });
        });
      };

      render(0);

      ScrollTrigger.create({
        trigger: rootRef.current,
        start: "top top",
        end: `+=${sectionHeight * safeItems.length}%`,
        pin: stickyRef.current,
        scrub,
        pinSpacing,
        invalidateOnRefresh: true,
        onUpdate: (self) => render(self.progress),
      });
    }, rootRef);

    return () => ctx.revert();
  }, [safeItems, scrub, pinSpacing, sectionHeight, leftRadiusX, leftRadiusY, rightRadiusX, rightRadiusY]);

  return (
    <section
      ref={rootRef}
      className={`circular-scroll-showcase ${className}`}
      style={{
        "--css-title-size": titleSize,
        "--css-card-width": `${imageCardWidth}px`,
        "--css-card-height": `${imageCardHeight}px`,
      }}
    >
      <div ref={stickyRef} className="circular-scroll-showcase__sticky">
        <div className="circular-scroll-showcase__inner">
          <div className="circular-scroll-showcase__left">
            <div className="circular-scroll-showcase__left-track">
              {safeItems.map((item) => (
                <div key={item.id} className="circular-scroll-showcase__left-item">
                  {item.title}
                </div>
              ))}
            </div>
          </div>

          <div className="circular-scroll-showcase__right">
            <div className="circular-scroll-showcase__right-track">
              {safeItems.map((item) => (
                <div key={item.id} className="circular-scroll-showcase__right-item">
                  <div className="circular-scroll-showcase__card">
                    <img src={item.image} alt={item.alt} className="circular-scroll-showcase__image" draggable="false" />
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default OrbitSlider;
